import React, { useEffect, useState } from "react";
import { Line, Bar } from "react-chartjs-2";
import { useDispatch, useSelector } from "react-redux";
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { getEachMechantProduct } from "../../features/product/productSlice";
import "chart.js/auto";
import { Button, Card, Space, Select, Tag, Table, Typography } from "antd";
import {
  BiFile,
  BiDownload,
  BiTrendingUp,
  BiDollarCircle,
  BiChevronDown,
} from "react-icons/bi";
import { getOrders } from "../../features/auth/authSlice";
import { config } from "../../utils/axiosconfig";

const { Text } = Typography;

const FinancialReport = () => {
  const dispatch = useDispatch();
  const [selectedYear, setSelectedYear] = useState("all");
  const [selectedMonth, setSelectedMonth] = useState("all");

  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));
    if (user) {
      dispatch(getEachMechantProduct(user._id));
      dispatch(getOrders(config));
    }
  }, [dispatch]);

  const productState = useSelector((state) => state?.product?.productsMerchant);
  const orderState = useSelector((state) => state?.auth?.orders);
  const user = useSelector((state) => state?.auth?.user);

  const IfilteredOrders =
    orderState?.orders?.filter((order) =>
      order?.cart?.some((item) => item.postedByUserId === user?._id),
    ) || [];

  const orders = IfilteredOrders;

  const filteredOrders = orders.filter((order) => {
    const orderDate = new Date(order.createdAt);
    const matchesYear =
      selectedYear === "all" ||
      orderDate.getFullYear() === parseInt(selectedYear);
    const matchesMonth =
      selectedMonth === "all" ||
      orderDate.getMonth() + 1 === parseInt(selectedMonth);
    return matchesYear && matchesMonth;
  });

  const getProductDetails = (productId) => {
    return (
      productState?.data?.find((product) => product._id === productId) || {}
    );
  };

  const totalRevenue = filteredOrders.reduce(
    (sum, order) => sum + order.totalPriceAfterDiscount,
    0,
  );
  const totalSales = filteredOrders.length;

  const monthlySales = {};
  filteredOrders.forEach((order) => {
    const month = new Date(order.createdAt).toLocaleString("default", {
      month: "short",
    });
    monthlySales[month] =
      (monthlySales[month] || 0) + order.totalPriceAfterDiscount;
  });

  const lineChartData = {
    labels: Object.keys(monthlySales),
    datasets: [
      {
        label: "Revenue Performance",
        data: Object.values(monthlySales),
        fill: true,
        backgroundColor: "rgba(37, 99, 235, 0.05)",
        borderColor: "#2563eb",
        pointBackgroundColor: "#ffffff",
        pointBorderColor: "#2563eb",
        pointHoverRadius: 6,
        pointRadius: 4,
        borderWidth: 2,
        tension: 0.4,
      },
    ],
  };

  const barChartData = {
    labels: Object.keys(monthlySales),
    datasets: [
      {
        label: "Inventory Outflow (Sales)",
        data: Object.values(monthlySales),
        backgroundColor: "#1e293b",
        borderRadius: 8,
      },
    ],
  };

  const generatePDF = (type) => {
    const doc = new jsPDF();
    doc.setFont("helvetica", "bold");
    doc.setFontSize(18);
    doc.text("Enterprise Financial Audit Report", 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(
      `Generated: ${new Date().toLocaleString()} | Merchant Node: ${user?.firstname} ${user?.lastname}`,
      14,
      28,
    );

    const columns = ["Date", "Node Identifier", "Valuation", "Review Status"];
    const rows = filteredOrders.map((order) => [
      new Date(order.createdAt).toLocaleDateString(),
      `${order.first_name} ${order.last_name}`,
      `${order.totalPriceAfterDiscount.toLocaleString()} ETB`,
      order.orderStatus.toUpperCase(),
    ]);

    autoTable(doc, {
      head: [columns],
      body: rows,
      startY: 35,
      theme: "striped",
      headStyles: { fillColor: [17, 24, 39], textColor: [255, 255, 255] },
      alternateRowStyles: { fillColor: [249, 250, 251] },
    });

    doc.save(`financial_audit_${type}_${Date.now()}.pdf`);
  };

  const tableColumns = [
    {
      title: "#TEMPORAL MARK",
      dataIndex: "createdAt",
      render: (date) => (
        <span className="font-mono text-[10px] font-black text-gray-400 uppercase">
          {new Date(date).toLocaleDateString()}
        </span>
      ),
    },
    {
      title: "CLIENT NODE",
      dataIndex: "client",
      render: (_, record) => (
        <span className="font-black text-gray-900 tracking-tight uppercase text-xs">
          {record.first_name} {record.last_name}
        </span>
      ),
    },
    {
      title: "VALUATION (ETB)",
      dataIndex: "totalPriceAfterDiscount",
      render: (val) => (
        <span className="font-black text-blue-600 tracking-tight text-xs">
          {val.toLocaleString()}
        </span>
      ),
    },
    {
      title: "LIFECYCLE STATUS",
      dataIndex: "orderStatus",
      render: (status) => (
        <Tag
          color={status === "pending" ? "orange" : "success"}
          className="rounded-full border-none px-3 font-bold text-[10px] uppercase"
        >
          {status}
        </Tag>
      ),
    },
  ];

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-500 bg-[#f7f7f8] min-h-screen">
      {/* Header Section */}
      <div className="flex justify-between items-end border-b border-gray-200 pb-6">
        <div>
          <h1 className="text-3xl font-black text-gray-900 tracking-tight">
            Financial Audit Node
          </h1>
          <p className="text-gray-500 font-medium tracking-tight">
            Revenue Analytics • Inventory Valuation • Fiscal Trace
          </p>
        </div>
        <Space>
          <Button
            icon={<BiDownload />}
            onClick={() => generatePDF("monthly")}
            className="rounded-xl font-bold uppercase tracking-tight text-[10px] h-11 px-6 border-gray-200"
          >
            Export Audit (Monthly)
          </Button>
          <Button
            type="primary"
            icon={<BiFile />}
            onClick={() => generatePDF("yearly")}
            className="bg-gray-900 rounded-xl font-bold uppercase tracking-tight text-[10px] h-11 px-6 border-none"
          >
            Export Audit (Yearly)
          </Button>
        </Space>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        <Card className="enterprise-card border-none shadow-sm">
          <div className="space-y-4">
            <div className="w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center text-blue-600">
              <BiTrendingUp size={20} />
            </div>
            <div>
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">
                Total Fiscal Revenue
              </p>
              <h2 className="text-2xl font-black text-gray-900 tracking-tight">
                {totalRevenue.toLocaleString()}{" "}
                <span className="text-xs text-gray-400">ETB</span>
              </h2>
            </div>
          </div>
        </Card>
        <Card className="enterprise-card border-none shadow-sm">
          <div className="space-y-4">
            <div className="w-10 h-10 rounded-xl bg-violet-50 flex items-center justify-center text-violet-600">
              <BiDollarCircle size={20} />
            </div>
            <div>
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">
                Operational Outflow
              </p>
              <h2 className="text-2xl font-black text-gray-900 tracking-tight">
                {totalSales}{" "}
                <span className="text-xs text-gray-400">Transactions</span>
              </h2>
            </div>
          </div>
        </Card>
      </div>

      {/* Filters */}
      <Card className="enterprise-card border-none shadow-sm bg-white p-4">
        <div className="flex gap-4">
          <Select
            size="large"
            value={selectedYear}
            onChange={setSelectedYear}
            suffixIcon={<BiChevronDown />}
            className="w-48 enterprise-select"
            placeholder="Select Fiscal Year"
          >
            <Select.Option value="all">All Fiscal Years</Select.Option>
            <Select.Option value="2025">Year 2025</Select.Option>
            <Select.Option value="2024">Year 2024</Select.Option>
          </Select>

          <Select
            size="large"
            value={selectedMonth}
            onChange={setSelectedMonth}
            suffixIcon={<BiChevronDown />}
            className="w-48 enterprise-select"
            placeholder="Select Temporal segment"
          >
            <Select.Option value="all">Full Temporal Cycle</Select.Option>
            {Array.from({ length: 12 }, (_, i) => (
              <Select.Option key={i + 1} value={String(i + 1)}>
                {new Date(0, i).toLocaleString("default", { month: "long" })}
              </Select.Option>
            ))}
          </Select>
        </div>
      </Card>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <Card
          title={
            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
              Revenue performance trace
            </span>
          }
          className="enterprise-card border-none shadow-sm h-[400px]"
        >
          <div className="h-full">
            <Line
              data={lineChartData}
              options={{
                maintainAspectRatio: false,
                plugins: { legend: { display: false } },
                scales: {
                  y: { border: { display: false }, grid: { color: "#f1f5f9" } },
                  x: { border: { display: false }, grid: { display: false } },
                },
              }}
            />
          </div>
        </Card>
        <Card
          title={
            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
              transaction volume analytics
            </span>
          }
          className="enterprise-card border-none shadow-sm h-[400px]"
        >
          <div className="h-full">
            <Bar
              data={barChartData}
              options={{
                maintainAspectRatio: false,
                plugins: { legend: { display: false } },
                scales: {
                  y: { border: { display: false }, grid: { color: "#f1f5f9" } },
                  x: { border: { display: false }, grid: { display: false } },
                },
              }}
            />
          </div>
        </Card>
      </div>

      <Card
        title={
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
            Ledger Transaction History
          </span>
        }
        className="enterprise-card border-none shadow-sm p-4"
      >
        <Table
          columns={tableColumns}
          dataSource={filteredOrders}
          pagination={{ pageSize: 12 }}
          className="enterprise-table"
        />
      </Card>
    </div>
  );
};

export default FinancialReport;
